import React from "react";

function About() {
  return (
    <>
      <main className="container">
        <h1 className="text-center mt-5 mb-5 border-bottom">About Me</h1>
        <div className="row">
          <div className="col">
            <img src="/assets/profilemain.jpg" alt="Profile Image" style={{
              borderRadius: "50%", width: "60%", height:"50%"
            }}/>
          </div>
          <div className="col-md-6"></div>
        </div>
      </main>
    </>
  );
}

export default About;
